import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"风暴之女","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/风暴之女.md","filePath":"4.资源分区/1.血统与训练/1.生理类/风暴之女.md"}'),s={name:"4.资源分区/1.血统与训练/1.生理类/风暴之女.md"};function o(d,b,l,_,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"风暴之女",tabindex:"-1"},[t("风暴之女 "),r("a",{class:"header-anchor",href:"#风暴之女","aria-label":'Permalink to "风暴之女"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="风暴之女-1" tabindex="-1">风暴之女 <a class="header-anchor" href="#风暴之女-1" aria-label="Permalink to &quot;风暴之女&quot;">​</a></h1><p>风暴之女<br> 魔幻本质<br> 血统<br> 某一天，某一刻，在某个地方<br> 有个孩子死去了</p><p>这是完全与你无关的事<br> 那个孩子也只是死去了而已<br> 无需铭记，也不会被刻入历史<br> 这个世界始终被死所包围着。</p><p>你会觉得悲伤么，你会感到痛苦么？<br> 他人的死，无论如何都只是别人的事。<br> 不如说，它必须是别人的事。<br> 如不然，人类将轻易地被他者之死的悲伤所压垮。</p><p>没关系的。<br> 我是风暴与夜的魔女，记忆力可是非常好的。</p><p>没错，所以我会记得。<br> 记得这个孩子度过了怎样的人生，<br> 记得他因何而喜悦，又为何而悲伤。</p><p>我会一直记得，<br> 那些未能刻入历史的孩子们。</p><p>由我来记住他们。</p><p>购买前置：女性 风度5<br> 特殊的，若你购买了此血统，则无法购买从者改造-加拉哈德</p><p>D+600 <br> 莉莉丝在众多传说中都与‘风暴’‘夜枭’有着强关联，莉莉丝是风暴与夜晚相关的女恶魔，有性感的身材，美妙的歌喉，绝美的脸庞，却拥有不可忽视的非人特征。在攻击人时，外形常常被描述为鸟首人身、背生双翼、脚为鸟爪，象征着黑暗与死亡。而在部分艺术作品中，也有着莉莉丝手持毒蛇，立于狮背，也与猫头鹰的夜行性和猛禽特征呼应。<br> 效果：你的生物类型永远转变为黑暗生物，并且你永久减少一点意志上限。并且获得【黑暗视觉】<br> 你现在获得了一个新的能量池【夜幕】关键属性为风度+耐力，此能量池为魔力的变体。<br> 【夜幕】的使用方法如下<br> 【融入黑暗】在攻击时消耗1点夜幕，使得这次攻击转变为黑暗能量伤害。<br> 【身披夜幕】在受到攻击时消耗1点夜幕，使你在应对此次攻击时天生防御提高2点。<br> 【憎恶】在攻击时消耗2点夜幕，你此次攻击额外获得1点附加成功。<br> 【夜幕】的回复方法<br> 你可以在一个有风的地方进行短休，进行风度属性检定恢复检定出目的夜幕，也可以在长休息后恢复至满值。</p><p>莉莉丝的另一个侧面是梦魔之母，在此血统中并不会多显示其作为梦魔的权能，但是你若完全接受其血脉中的力量，你的皮肤就会不可控制的变成淡灰色，头上会长出恶魔标志性的角，若你想，你可以选择不改变容貌，但是依旧无法改变你拥有者梦魔之母的血，现在由于你由内而外散发出来的魅力，在初次见面时，让所有基础友好度不低于冷淡的人对你的态度上升一级（不可升至极端）。</p><p>你现在若没有武器，可以消耗1点魔力制造一个武器伤害3L，由夜幕构成的黑色魔力长剑，若现在持有者已经有了武器类型为剑的武器的话，则增加3L武器伤害给自己手持的武器。</p><p>C+1200<br> 现在你终于正式习惯了这个血脉所给你带来的力量，此时，作为风暴之女和梦魔之母的‘血亲’你在对于【夜幕】本身的使用也变得更加的纯熟，你现在获得新的能量池用法。<br> 【如舞动之翼】：消耗5点夜幕，你在背后生出猫头鹰一样的双翼，你获得了持续一个场景（15分钟）的飞行能力，机动性为笨拙<br> 【邪恶之女】：消耗3点夜幕，你的这次攻击获得【破魔5】</p><p>在此时你可以激发自己最纯正的风暴之女血脉，你现在获得技能【风暴之女】<br> 【风暴之女】：你支付6点魔力，消耗一个杂技动作让自己的身体进行【夜枭化】，你的手指增加了指节，变得非人，你的小臂，手，小腿和脚都被黑色的魔力覆盖，而小腿和脚更是变异成了鸟兽的爪子，但是其上却覆盖着黑色的羊毛，下腰处也长出了蛇骨一样的尾巴，你的体积现在提高3，这个体积无法为你带来生命值，你的全身现在被视为3L的天生武器，并且你的攻击现在额外附带【破甲5】</p><p>你所运用的这些魔力并不仅仅是带给你强横的体质，它们在你体内与外部的玛娜共同蕴养你的身体，也许是使你的身体更加的富有诱惑性，也许是增强你的力量，也许是。。。单纯的保护你，就像是高岭之花一般不可侵犯。现在每经历一场一片，你便可以获得1点风度检定上的附加成功/1点力量检定上的附加成功/1活体护甲，而活体护甲提供的防御则是不提供盔甲防御转而提供天生防御。 此效果在你购买此等级血统时选定，选定后不可更改。</p><p>B+2400<br> 是对玛修·基列莱特的些许不足道的祈愿，<br> 或是射入心脏的冰之子弹。<br> 二人决不会真正理解彼此，注定永远错过，彼此擦肩。<br> 无论如何渴盼，我都终将会憎恨你吧，<br> 就像你也会憎恨我一样。<br> 就是这样的，献给玛修·基列莱特的礼物。<br> 随着你与血脉的融合，陌生的记忆涌入你的脑海，你不清楚谁是玛修，但是。。。但是。。。你似乎终于理解了这个深深植入在自己血脉中憎恨的来源了。<br> 就让我（我们）为你献上这彷徨不定的祈祷。<br> 你获得新的能量池用法。<br> 【身披夜幕II】一轮一次，消耗10点夜幕，强化自己的肉体，该轮获得等同于自身耐力属性点的天生防御。<br> 【增恶II】一轮一次，消耗10点夜幕，将其强化在自己的武器上，该轮发动的第一次攻击获得等用于自身风度属性点的增强加值。<br> 【如舞动之翼II】你可以用一个自由动作支付7点夜幕，你在背后生出猫头鹰一样的双翼，你获得了持续一个场景（15分钟）的飞行能力，机动性为普通。</p><p>【风暴之女II】你可以支付10点魔力，消耗一个杂技动作让自己的身体进行【夜枭化】，你的手指增加了指节，变得非人，你的小臂，手，小腿和脚都被黑色的魔力覆盖，而小腿和脚更是变异成了鸟兽的爪子，但是其上却覆盖着黑色的羊毛，下腰处也长出了蛇骨一样的尾巴，现在，你除了获得C级【风暴之女】所获得的能力效果之外，你在攻击时获得【湮灭】，并且现在在攻击时额外获得基于自己力量属性一半的破甲。</p><p>专属武器<br> 如丑陋之恋<br> 魔幻本质<br> 概念武装<br> 只有在购买了风暴之女血统后才可以购买此武器<br> 概述此武器为莉莉丝被称之为‘夜之魔女’的权能的具象化，她徘徊于荒野，引诱男子吞吃婴儿的形象广为流传。<br> ‘不会啦不会啦，我和亚当也不认识，你们（人类）对我的误解究竟能有多深？’<br> 该武器为差价升级，高级效果替换低级特性，下不赘述。</p><p>D+500<br> 此武器为概念武装，从外形上看起来像是一个黑色的皮质手套，在战斗时黑色的魔力则会蔓延至整个小臂。并且变为一个体积为5，武器伤害7L，具有【双手】特性，分类为重剑的黑色哥特风巨型剪刀，剪刀的刀刃与一般的剪刀持握处中间有个爱心形状的链接，爱心的中间则是做了一个持握的握把。<br> 【概念武装】：由于其本身就是由魔力制成的概念武装，攻击灵体等自然不在话下，此武器拥有【法破】特性<br> 【特击技巧提升】：由于其魔力的强化，使用者在使用此武器进行攻击时，获得基于自己传奇敏捷*1的高速。</p><p>C+1000<br> 现在如丑陋之恋的武器伤害提升至12L，在战斗时黑色的魔力则会蔓延至整个小臂。并且变为一个体积为5，武器伤害12L，具有【双手】特性，分类为重剑的黑色哥特风巨型剪刀，剪刀的刀刃与一般的剪刀持握处中间有个爱心形状的链接，爱心的中间则是做了一个持握的握把。其变化而出的剪刀则是在其刀刃的末端有喷溅上去的粉色液体，剪刀的持握处用锁链链接着一个鸟笼形状的吊饰，里面则固定着一个黑曜石形状的小猫头鹰。<br> 【概念武装】：由于其本身就是由魔力制成的概念武装，攻击灵体等自然不在话下，此武器拥有【法破】特性<br> 【特击技巧提升】：由于其魔力的强化，使用者在使用此武器进行攻击时，获得基于自己传奇敏捷*1的高速。并且在攻击时获得【9加骰】</p><p>B+2000<br> 现在如丑陋之恋的武器伤害提升至17L，在战斗时黑色的魔力则会蔓延至整个小臂。并且变为一个体积为5，武器伤害17L，具有【双手】特性，分类为重剑的黑色哥特风巨型剪刀，剪刀的刀刃与一般的剪刀持握处中间有个爱心形状的链接，爱心的中间则是做了一个持握的握把。其变化而出的剪刀则是在其刀刃的末端有喷溅上去的粉色液体，剪刀的持握处用锁链链接着一个鸟笼形状的吊饰，里面则固定着一个黑曜石形状的小猫头鹰。而整个剪刀的被似蛇似龙的纹样覆盖，持握处也有蛇鳞一样的纹样方便持握。<br> 【概念武装】：由于其本身就是由魔力制成的概念武装，攻击灵体等自然不在话下，此武器拥有【法破】特性。<br> 【鲜血渴望】：蛇是一种狡猾的生物，武器之中的蛇灵渴望着敌人的鲜血，你以该武器进行的攻击获得【吸血3】<br> 【裁断】：现在寄宿在武器上的夜枭精准的找到了敌人的弱点，你使用剪刀可以轻易的剪断对面的生命，你的武器获得【幻灭】<br> 【予你这彷徨无定的祈祷】其本身是将自身化作子弹的一种宝具，起因是对某人的憎恨，是对其微不足道的祈愿，也是献给她的礼物，但是由于这个侧面并没有如此之深的恨意，所以仅仅只是将这份恨意藏在了武器中，作为武器的概念出现，被这把武器杀死的单位无法以S级及以下的效果复活。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',23)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
